final:
module top_module (
    input [1:0] h,
    output reg not_k
);

    always @(*) begin
        case (h)
            2'b00: not_k = 0;
            2'b01: not_k = 1;
            2'b10: not_k = 1;
            2'b11: not_k = 1;
            default: not_k = 0; // Default case
        endcase
    end
endmodule
